#include <stdio.h>

double myPow(double x, int n) {
    if (n == 0) return 1;
    if (n < 0) {
        x = 1 / x;
        n = -n;
    }
    double ans = 1;
    for (int i = 0; i < n; i++) {
        ans *= x;
    }
    return ans;
}

int main() {
    printf("%.4f\n", myPow(2.0000, 10));
    printf("%.4f\n", myPow(2.0000, -2));
    return 0;
}

